        const filename = `journey-snap-${url.hostname}-${now.replace(invalidChars, '-')}.png`;

        // message the background page to retrieve the default download directory
        chrome.runtime.sendMessage({ action: 'getDownloadDirectory' }, function(response) {
          if (chrome.runtime.lastError) {
            console.error(chrome.runtime.lastError.message);
            return;
          }

          const defaultDirectory = response.downloadDirectory;

          chrome.downloads.download({
