using namespace std;

const int MAXN = 1000; // maximum number of rows
const int MAXM = 1000; // maximum number of columns

int N, M; // dimensions of the grid
bool grid[MAXN][MAXM]; // boolean grid
bool visited[MAXN][MAXM]; // visited array

void dfs(int i, int j) {
    visited[i][j] = true;
    int di[4] = {0, 0, 1, -1};
    int dj[4] = {1, -1, 0, 0};
    for (int k = 0; k < 4; k++) {
        int ni = i + di[k], nj = j + dj[k];
        if (ni >= 0 && ni < N && nj >= 0 && nj < M && grid[ni][nj] && !visited[ni][nj]) {
            dfs(ni, nj);
        }
    }
}

bool is_connected() {
    // check if each true element is connected to another true element
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (grid[i][j] && !visited[i][j]) {
                dfs(i, j);
            }
        }
    }
    // check if there are any false elements that are not connected to any true element
    bool has_false = false;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (!visited[i][j] && grid[i][j]) {
                has_false = true;
                break;
            }
        }
        if (has_false) break;
    }
    return !has_false;
}

int main() {
    // read input
    cin >> N >> M;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            cin >> grid[i][j];
        }
    }
    // initialize visited array
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            visited[i][j] = false;
        }
    }
    // check if each true element is connected to another true element
    if (is_connected()) {
        cout << "Each true element is connected to another true element." << endl;
    } else {
        cout << "There are false elements that are not connected to any true element." << endl;
    }
    return 0;
}
