1. Create an Angular directive called `chartDownload.directive.ts` in a shared location (e.g., `src/app/shared/directives/`):
```typescript
import { Directive, ElementRef, Input, HostListener } from '@angular/core';
import domtoimage from 'dom-to-image';
import jsPDF from 'jspdf';

@Directive({
  selector: '[appChartDownload]'
})
export class ChartDownloadDirective {
  // Input property to specify the chart container selector (ID or class)
  @Input('appChartDownload') chartContainerSelector: string;

  constructor(private el: ElementRef) {}

  @HostListener('click')
  onClick() {
    if (!this.chartContainerSelector) {
      console.error('Chart container selector is not specified.');
      return;
    }

    // Get the chart container element using the provided selector
    const chartContainer = document.querySelector(this.chartContainerSelector);

    if (!chartContainer) {
      console.error('Chart container not found.');
      return;
    }

    // Capture the chart as an image
    domtoimage.toPng(chartContainer)
      .then(dataUrl => {
        // Create a new PDF document
        const pdf = new jsPDF('p', 'mm', 'a4');

        // Add the captured image to the PDF document
        pdf.addImage(dataUrl, 'PNG', 15, 15, 180, 180);

        // Save the PDF file
        pdf.save('chart.pdf');
      })
      .catch(error => {
        console.error('Error capturing chart:', error);
      });
  }
}
```
