CREATE PROCEDURE [eventdispatcher].[GetPendingIntegrationEvents]
    @Top INT
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY

        DECLARE @TRANCOUNT_AT_START INT;
        SET @TRANCOUNT_AT_START = @@TRANCOUNT;
        IF @TRANCOUNT_AT_START <> 0
            SAVE TRANSACTION GetPendingIntegrationEvents;

        IF @Top IS NULL
        BEGIN
            DECLARE @Message NVARCHAR(255) = N'Parameter @Top is NULL';
            THROW 150000, @Message, 1;
        END;

        DECLARE @UpdatedIntegrationEventLog TABLE 
        (
            IntegrationEventLogID INT NOT NULL PRIMARY KEY,
            EventStatus INT NOT NULL
        );

        BEGIN TRAN

        UPDATE TOP (@Top) [dbo].[IntegrationEventLog]
        SET EventStatus = 1
        OUTPUT inserted.IntegrationEventLogID, inserted.EventStatus INTO @UpdatedIntegrationEventLog
        WHERE [EventStatus] = 0
        ORDER BY [CreatedDateUTC] ASC;

        COMMIT

        SELECT [IntegrationEventLogID],
               [CreatedDateUTC],
               [EventId],
               [Content],
               [EventTypeName],
               [EventStatus],
               [TransactionId],
               [FailureCount],
               [ErrorMessage],
               [UpdatedDateUTC]
        FROM [dbo].[IntegrationEventLog] iel
        JOIN @UpdatedIntegrationEventLog uiel ON iel.IntegrationEventLogID = uiel.IntegrationEventLogID;
    END TRY
    BEGIN CATCH
        DECLARE @XACT_STATE INT;
        SELECT @XACT_STATE = XACT_STATE();
        IF @XACT_STATE = -1
            ROLLBACK;
        IF @XACT_STATE = 1
           AND @TRANCOUNT_AT_START = 0
