import { useState } from 'react';
import axios from 'axios';
import { useStore } from '../store';

const SearchForm = () => {
  const [query, setQuery] = useState('');
  const { setUsers } = useStore();

  const handleSearch = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    try {
      const { data } = await axios.get(`https://api.github.com/search/users?q=${encodeURIComponent(query)}`);
      setUsers(data.items);
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <form onSubmit={handleSearch} className="flex flex-row items-center space-x-2">
      <div className="relative w-full">
        <input
          type="text"
          placeholder="Search GitHub users"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          className="block w-full border-gray-300 rounded-md shadow-sm pl-10 pr-3 py-2 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
        />
        {query && (
          <button
            type="button"
            onClick={() => setQuery('')}
            className="absolute inset-y-0 right-0 pr-3 flex items-center"
          >
            <svg
              className="h-5 w-5 text-gray-400"
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 20 20"
              fill="currentColor"
              aria-hidden="true"
            >
              <path
                fillRule="evenodd"
                d="M5.293 6.707a1 1 0 011.414 0L10 8.586l3.293-3.293a1 1 0 011.414 1.414L11.414 10l3.293 3.293a1 1 0 01-1.414 1.414L10 11.414l-3.293 3.293a1 1 0 01-1.414-1.414L8.586 10 5.293 6.707z"
                clipRule="evenodd"
              />
            </svg>
          </button>
        )}
      </div>
      <button type="submit" className="px-4 py-2 border border-transparent text-base font-medium rounded-md text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500">
        Search
      </button>
      {setUsers.length === 0 && (
        <div className="px-2 py-1 bg-red-100 text-red-800 rounded-md">No users found.</div>
      )}
    </form>
  );
};

export default SearchForm;
```
In this example, the condition `setUsers.length === 0` is used to check if the `users` array is empty. If it is, a message saying "No users found." is rendered. Note that this message is only displayed after the user has submitted a search query.

